using sv_9e9881e777754a4b8ac000e32bf0af44;
using sv_9e9881e777754a4b8ac000e32bf0af44.Client.Pages;
using sv_9e9881e777754a4b8ac000e32bf0af44.Components;

var builder = WebApplication.CreateBuilder(args);

