@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>

        <h2>Roles</h2>
        <ul>
            @foreach (var claim in context.User.Claims.Where(c => c.Type == System.Security.Claims.ClaimTypes.Role))
            {
                <li>@claim.Value</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the Editor page. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<p>This page is accessible to any authenticated user.</p>

